# shapes.spy - Shape classes with virtual properties and methods
@abstract
class Shape:
    _name: str

    def __init__(self, name: str):
        self._name = name

    @virtual
    def describe(self) -> str:
        return f"Shape: {self._name}"

    @virtual
    def scale(self, factor: float) -> Shape:
        return self

    @abstract
    def get_area(self) -> float:
        ...

    property get name(self) -> str:
        return self._name

@abstract
class Polygon(Shape):
    sides: int

    def __init__(self, name: str, sides: int):
        super().__init__(name)
        self.sides = sides

    @override
    def describe(self) -> str:
        return f"Polygon({self.sides} sides): {self._name}"

class Circle(Shape):
    radius: float

    def __init__(self, r: float):
        super().__init__("Circle")
        self.radius = r

    @override
    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def scale(self, factor: float) -> Shape:
        return Circle(self.radius * factor)

    def __str__(self) -> str:
        return f"C({self.radius})"

class Rectangle(Polygon):
    width: float
    height: float

    def __init__(self, w: float, h: float):
        super().__init__("Rectangle", 4)
        self.width = w
        self.height = h

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def scale(self, factor: float) -> Shape:
        return Rectangle(self.width * factor, self.height * factor)

    def __str__(self) -> str:
        return f"R({self.width}x{self.height})"

