# factories.spy - Factory classes and generators
from shapes import Shape, Circle, Rectangle, Polygon
from utils import Color, Point, BoundingBox

def create_default_circle() -> Circle:
    return Circle(5.0)

def create_unit_square() -> Rectangle:
    return Rectangle(1.0, 1.0)

class ShapeGenerator:
    _count: int

    def __init__(self):
        self._count = 0

    def generate_circle(self, radius: float) -> Circle:
        self._count = self._count + 1
        return Circle(radius)

    def generate_rectangles(self, num: int) -> list[Rectangle]:
        result: list[Rectangle] = []
        i: int = 0
        while i < num:
            r: Rectangle = Rectangle((i + 1) * 10.0, (i + 1) * 5.0)
            result.append(r)
            i = i + 1
        return result

    def get_count(self) -> int:
        return self._count

    def __iter__(self) -> Shape:
        yield Circle(1.0)
        yield Circle(2.0)
        yield Rectangle(3.0, 4.0)

def create_bounding_box_for_shapes(shapes: list[Shape]) -> BoundingBox:
    if len(shapes) == 0:
        return BoundingBox(Point(0.0, 0.0), Point(0.0, 0.0))

    min_x: float = 0.0
    min_y: float = 0.0
    max_x: float = 0.0
    max_y: float = 0.0
    first: bool = True

    for s in shapes:
        area: float = s.get_area()
        side: float = area ** 0.5
        if first:
            min_x = -side
            min_y = -side
            max_x = side
            max_y = side
            first = False
        else:
            if -side < min_x:
                min_x = -side
            if -side < min_y:
                min_y = -side
            if side > max_x:
                max_x = side
            if side > max_y:
                max_y = side

    return BoundingBox(Point(min_x, min_y), Point(max_x, max_y))
